code.setup:
import { gsap } from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
gsap.registerPlugin(ScrollTrigger);

code.linear:
// Linear — esquerda para direita
gsap.from('.card', {
  opacity: 0,
  y: 50,
  scale: 0.96,
  stagger: {
    amount: 0.5,   // tempo total distribuído (todos os cards em 0.5s)
    from: 'start', // 'start' | 'end' | 'center' | 'random'
  },
  duration: 0.65,
  ease: 'power3.out',
  scrollTrigger: {
    trigger: '.cards-grid',
    start: 'top 78%',
  }
});

code.grid_from_center:
// Grid stagger — do centro para fora (ex: 3 colunas x 4 linhas)
const COLS = 3;
const ROWS = Math.ceil(document.querySelectorAll('.grid-item').length / COLS);

gsap.from('.grid-item', {
  opacity: 0,
  scale: 0.85,
  y: 30,
  stagger: {
    amount: 0.8,
    grid: [ROWS, COLS],
    from: 'center',
  },
  duration: 0.55,
  ease: 'back.out(1.4)',
  scrollTrigger: {
    trigger: '.grid-container',
    start: 'top 75%',
  }
});

code.random:
// Stagger aleatório — caótico mas controlado
gsap.from('.feature-item', {
  opacity: 0,
  y: 40,
  rotation: () => Math.random() * 6 - 3,
  stagger: {
    amount: 0.6,
    from: 'random',
  },
  duration: 0.7,
  ease: 'power2.out',
  scrollTrigger: {
    trigger: '.features',
    start: 'top 80%',
  }
});

code.flip_3d:
// Flip 3D — usar com moderação (máx 4-6 cards)
gsap.from('.flip-card', {
  rotateY: 90,
  opacity: 0,
  transformOrigin: 'left center',
  stagger: 0.15,
  duration: 0.7,
  ease: 'power3.out',
  scrollTrigger: {
    trigger: '.flip-container',
    start: 'top 80%',
  }
});
// Requer no CSS: .flip-container { perspective: 1200px; }

css_helpers:
/* Container com perspectiva para efeitos 3D */
.flip-container {
  perspective: 1200px;
}

/* Gap consistente para grids */
.cards-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1.5rem;
}
